while d <= end:
    if d.weekday() < 5:
        dates.append(d)
    d += datetime.timedelta(days=1)

total = len(dates)
editions_dir = ROOT / "editions"
archive = []

for idx, dt in enumerate(dates):
    vol = idx + 1
    iso = dt.isoformat()
    wd = WD[dt.weekday()]
    date_ko = f"{dt.year}년 {dt.month}월 {dt.day}일 ({wd})"
    label = f"Vol.{vol:02d}"
    prev = (dt - datetime.timedelta(days=1)).isoformat()
    if dt.month == 6:  # 6월은 실제 뉴스 풀(날짜 필터)
        news = mk_topic_real("news", "AI 최신 소식", "📰", "blue",
                             "발행일 기준 지난 24시간의 주요 AI 소식.", NEWS_REAL, dt)
        every = mk_topic_real("everyone", "비개발자를 위한 AI 소식", "🧭", "green",
                              "지난 24시간 소식 중, 오늘 바로 적용·시도해볼 만한 것.", EVERY_REAL, dt)
    else:              # 그 외(5월)는 데모 풀
        news = mk_topic("news", "AI 최신 소식", "📰", "blue",
                        "발행일 기준 지난 24시간의 주요 AI 소식.", NEWS_HL, NEWS_ART, idx, iso, prev)
        every = mk_topic("everyone", "비개발자를 위한 AI 소식", "🧭", "green",
                         "지난 24시간 소식 중, 오늘 바로 적용·시도해볼 만한 것.", EVERY_HL, EVERY_ART, idx, iso, prev)
    # 직무별 활용(상시) — 모든 호 공통
    planner = mk_topic_role("planner", "기획자를 위한 AI 소식", "💡", "purple", "기획 업무에 바로 쓰는 AI 활용 사례.", PLANNER_POOL, idx)
    data = mk_topic_role("data", "데이터 분석을 위한 AI 소식", "📊", "orange", "코드 없이 데이터 업무에 쓰는 AI 활용 사례.", DATA_POOL, idx)
    pm = mk_topic_role("pm", "PM을 위한 AI 소식", "📋", "pink", "PM 업무에 바로 쓰는 AI 활용 사례.", PM_POOL, idx)
    nl = {
        "meta": {
            "icon": "🗞️", "edition": label, "cadence": "일간",
            "date": date_ko, "curator": "러닝 에이전트 (Claude Cowork)", "reader": "메이커준",
            "title": ["데일리 ", "AI 뉴스레터"],
            "lead": "발행일 기준 지난 24시간의 AI 소식과 직무별 활용을 탭으로 나눠 전합니다. 탭마다 ‘딱 하나의 핵심’을 크게, ‘자세히 보기’엔 예시와 함께 길게 풀어 담았어요.",
            "greeting": "안녕하세요! 오늘은 ① 업계 주요 AI 소식과 ② 비개발자·기획·데이터·PM 직무별 활용을 탭으로 나눠 담았어요. 각 탭 맨 위 큰 카드가 <b>그 탭의 핵심</b>이고, ‘자세히 보기’엔 따라 할 예시와 샘플 한마디까지 길게 설명했습니다.",
        },
        "topics": [news, every, planner, data, pm],
    }
    obj = "const NEWSLETTER = " + json.dumps(nl, ensure_ascii=False, indent=2) + ";"
    html = re.sub(r"const NEWSLETTER = \{.*?\n\};", lambda m: obj, TPL, count=1, flags=re.DOTALL)
    (editions_dir / f"{iso}.html").write_text(html, encoding="utf-8")
    archive.append({"date": iso, "weekday": wd, "label": label,
                    "title": f"{news['highlight']['title']} · {every['highlight']['title']}"[:60],
                    "topics": ["AI 최신 소식", "비개발자를 위한 AI 소식"], "href": f"editions/{iso}.html"})

archive.reverse()
ARCHIVE = {
    "meta": {
        "icon": "🗞️", "title": ["데일리 ", "AI 뉴스레터"],
        "lead": "러닝 에이전트가 내 관심사에 맞춰 매일(영업일) 발행하는 개인화 AI 뉴스레터. 지난 24시간의 주요 소식을 골라 담고, 지난 호를 여기에 모아둡니다.",
        "owner": "메이커준", "cadence": "매일(영업일)",
    },
    "editions": archive,
}
index_path = ROOT / "index.html"
idx_html = index_path.read_text(encoding="utf-8")
arch_obj = "const ARCHIVE = " + json.dumps(ARCHIVE, ensure_ascii=False, indent=2) + ";"
idx_html = re.sub(r"const ARCHIVE = \{.*?\n\};", lambda m: arch_obj, idx_html, count=1, flags=re.DOTALL)
index_path.write_text(idx_html, encoding="utf-8")

print(f"generated {total} editions: {dates[0].isoformat()} ~ {dates[-1].isoformat()}")
print(f"archive entries: {len(archive)}")
